import json

input_data = _items[0]["json"]

raw = (input_data.get("stdout") or "").strip()

try:
    parsed = json.loads(raw)
except Exception as e:
    parsed = {
        "status": "parse_error",
        "parse_error": str(e),
    }

if parsed.get("status") == "success":
    agent_response = parsed.get("summary")
else:
    agent_response = f"ERROR {parsed.get('error') or parsed.get('parse_error')}"

return [
    {
        "json": {
            "output": agent_response,  
            "status": parsed.get("status"),
            "pkl_path": "/home/node/.n8n/ml_agent/train_test_split.pkl"
        }
    }
]
